"""
MKT Original Language Commentary — Isaiah chapters 5–8
Run: python3 scripts/zc-original-isaiah-5-8.py

Key decisions in this range:
- Ch 5: šîrâ (song) opens with a love-song frame that turns into a legal indictment;
  the vineyard parable structure is literary mashal, not allegory — Israel is the vineyard,
  YHWH the owner; the six woe-oracles (hôy, vv.8,11,18,20,21,22) form a catalog of
  covenant violations parallel to the Deuteronomic curses.
- Ch 6: qādôš (holy) in tripled form (v3) is unique in the Hebrew Bible — normally
  repetition is doubled (Jer 22:29); the triple is the highest possible superlative.
  hinnēnî šĕlaḥēnî (v8: "Here I am, send me") is a volitional response, not a compelled one.
  The hardening commission (vv9-10) is the most-quoted OT passage in the NT.
- Ch 7: ʿalmâ (v14) vs. bĕtûlâ: the LXX choice of parthenos was not a translation error
  but was within the semantic range of ʿalmâ; the Immanuel sign bridges the immediate
  Ahaz situation and the ultimate fulfillment in Christ (Matt 1:23).
- Ch 8: maggēpâ (stumbling stone, v14) language absorbed into NT Christology (Rom 9:33;
  1 Pet 2:6-8); hinnēh ʾānōkî wĕhayĕlādîm (v18) directly cited in Heb 2:13.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for isaiah.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {
  "5": {
    "1": '<p><strong>šîrat dôdî</strong> = "song of my beloved/love-song." <em>Šîr</em> (H7892) = song; <em>dôd</em> (H1730) = beloved, loved one (the word of the Song of Solomon). The prophecy opens as a love poem, luring the audience before the legal indictment unfolds. <strong>karmô</strong> = "his vineyard" — <em>kerem</em> (H3754) always implies cultivated care and investment. <strong>bĕqeren ben-šāmen</strong> = "on a horn of a son of oil/fertility" — the most fertile hillside, a sunny south-facing slope. Every advantage was given.</p>',
    "2": '<p><strong>wayyĕʿazkĕqēhû</strong> — Piel of <em>ʿāzaq</em> (H5823) = to dig/cultivate thoroughly, a rare verb found only here. <strong>wayyĕsaqqĕlēhû</strong> — Piel of <em>sāqal</em> = to clear of stones — a major labor investment. <strong>šôrēq</strong> (H8321) = the finest variety of red grape vine. <strong>migdāl</strong> = watchtower; <strong>yāqeḇ</strong> = wine vat hewn in rock. Every element — clearing, planting, tower, vat — demonstrates total preparatory commitment.</p><p><strong>wayyĕqaw laʿăśôt ʿănāḇîm wayyaʿaś bĕʾušîm</strong> = "he waited (<em>qāwâ</em> = hope-laden waiting) for grapes, but it produced wild grapes (<em>bĕʾušîm</em>)." <em>Bĕʾušîm</em> (H891) = worthless, stinking fruit — the antithesis of <em>šôrēq</em>. The disproportion between investment and return is the legal complaint.</p>',
    "3": '<p><strong>šipṭû-nāʾ bênî ûḇên karmî</strong> = "judge (<em>šāpaṭ</em>, imperative), please, between me and my vineyard." The audience is summoned as jury in the rîb (lawsuit). The rhetorical brilliance: they render judgment before realizing they are judging themselves.</p>',
    "4": '<p><strong>mah laʿăśôt ʿôd lĕkarmî wĕlōʾ ʿāśîtî bô</strong> = "What more was there to do for my vineyard that I have not done in it?" The question presupposes the answer: nothing. Every possible investment was made. The failure is entirely in the vineyard. This is the theological logic of prevenient grace preceding covenant failure.</p>',
    "5": '<p><strong>wĕʿattâ ʾôdîʿâ-nāʾ ʾetkem ʾēt ʾăšer-ʾănî ʿōśeh lĕkarmî</strong> = "And now let me tell you what I am about to do to my vineyard." The verdict: since the vineyard failed despite total care, the protection (<em>mĕśûkâ</em> = hedge; <em>gādēr</em> = wall) will be removed. Without the hedge, it becomes trampling-ground (<em>mirmās</em>).</p>',
    "6": '<p><strong>waʾăśîtēhû bātâ</strong> = "I will make it a waste." <strong>lōʾ yizzāmēr wĕlōʾ yēʿādēr</strong> = "it will not be pruned and not be hoed" — abandonment. <strong>wĕʿālu šāmîr wāšît</strong> = "thorns and briers shall come up" — <em>šāmîr wāšît</em> is Isaiah\'s repeated pair for curse-reversed-fruitfulness (7:23-25; 9:17; 10:17; 27:4; 32:13).</p><p><strong>wĕʿal heʿābîm ʾăṣawweh</strong> = "I will command the clouds not to rain on it" — YHWH commands the weather, unmasking his control of the cosmos. Israel\'s land productivity depends on covenant relationship with the one who controls rain (cf. Deut 11:14; 28:12,24).</p>',
    "7": '<p><strong>kî kerem YHWH ṣĕḇāʾôt bêt yiśrāʾēl</strong> — the allegory decoded: vineyard = Israel, choice vine = Judah. <strong>wayyĕqaw lĕmišpāṭ wĕhinnēh miśpāḥ</strong> — the devastating Hebrew wordplay: <em>mišpāṭ</em> (justice) → <em>miśpāḥ</em> (bloodshed); <em>ṣĕdāqâ</em> (righteousness) → <em>ṣĕʿāqâ</em> (cry of the oppressed). The near-rhyme makes the contrast both memorable and cutting: YHWH expected justice, found bloodshed; expected righteousness, heard the shriek of the oppressed.</p>',
    "8": '<p><strong>hôy</strong> (H1945) = the woe-oracle particle, originally a funeral cry, used by prophets to pronounce coming judgment as though it were already death. First woe targets land accumulation: <strong>maggîšê bayit bĕbayit</strong> = "those who join house to house." Land consolidation violated Mosaic land law (Lev 25; Num 27:1-11), under which each family held inalienable tribal allotment. <strong>ʿad ʾepem māqôm</strong> = "until there is no more place" — economic monopoly described as spatial displacement of the poor.</p>',
    "9": '<p>The divine oath formula: <em>bĕʾoznāy YHWH ṣĕḇāʾôt</em> = "in my ears, LORD of armies" — Isaiah hears YHWH swear. <strong>bāttîm rabbîm lĕšammâ yihyû</strong> = "many houses shall become a desolation (<em>šammâ</em>)" — the accumulated houses become the judgment. The collector of houses will find them all empty; the "great and fine" houses (<em>gĕdōlîm wĕṭōḇîm</em>) become great vacancies.</p>',
    "10": '<p><strong>kî ʿăśeret ṣimĕdê kerem yaʿăśû bat ʾeḥāt</strong> = "ten yokes of vineyard will produce one bath." A <em>ṣemed</em> = the area one yoke of oxen plows in a day. A single bath (ca. 6 gallons) from ten plots is catastrophic failure — a single plot should produce 300+ liters. <strong>wĕzeraʿ ḥōmer yaʿăśeh ʾêpâ</strong> = "a homer of seed will produce an ephah" — one-tenth yield. They hoarded land for agricultural dominance; the land itself will resist them.</p>',
    "11": '<p>Second woe: early-rising drinkers. <strong>maškîmê babbōqer šēkār yirdōpû</strong> = "those who rise early to pursue (<em>rādap</em> = chase after) strong drink (<em>šēkār</em>)." The urgency of <em>maškîmê</em> (to rise early, H7925) applied to alcohol consumption rather than prayer or work satirizes misplaced devotion. <strong>mĕʾaḥărê bannešep</strong> = "who tarry late in the evening" — bookending the day with drunkenness.</p>',
    "12": '<p><strong>wĕhāyâ kinnôr wāneḇel tōp wĕḥālîl wāyyin mištêhem</strong> = "the harp, lute, tambourine, flute, and wine are at their feasts." The full musical catalog — <em>kinnôr</em> (lyre), <em>neḇel</em> (harp), <em>tōp</em> (tambourine), <em>ḥālîl</em> (flute) — is not condemned as such but as a substitute for attending to YHWH\'s work in history. <strong>wĕʾēt pōʿal YHWH lōʾ yaḇbiṭû</strong> = "but they do not regard the work (<em>pōʿal</em>) of YHWH" — to miss God\'s work in history is spiritual blindness at the deepest level.</p>',
    "13": '<p><strong>lākēn gālâ ʿammî mibbelî-dāʿat</strong> = "Therefore my people will go into exile for lack of knowledge (<em>bĕlî-dāʿat</em>)." <em>Gālâ</em> (H1540) = to go into exile — the technical term for Assyrian/Babylonian deportations. The cause: not factual ignorance but failure of relational <em>daʿat</em> (knowing YHWH, cf. 1:3; Hos 4:6). <strong>wĕkaḇĕdô mĕtê rāʿāb</strong> = "their honored ones will die of famine" — social reversal: wealthy feasters will starve.</p>',
    "14": '<p><strong>lākēn hirḥîḇâ šĕʾôl napšāh</strong> = "therefore Sheol has enlarged its throat (<em>napšāh</em>, lit. its soul/throat)." Sheol is personified as an insatiable monster opening its gullet (cf. Hab 2:5). The death-as-consuming-beast motif appears in Canaanite mythology (Mot); Isaiah deploys it to describe the scale of coming judgment where even the honored (v13) are swallowed.</p>',
    "15": '<p><strong>wayyišaḥ ʾādām wayyišpal-ʾîš</strong> = "mankind will be humbled (<em>šāḥâ</em>) and people brought low (<em>šāpal</em>)" — both verbs describe descending from height, reversing the exaltation sought by the land-grabbers and revelers. <strong>wĕʿênê gĕḇōhîm tišpalnâ</strong> = "and the eyes of the haughty will be brought low" — the proud gaze that looked down at the poor is itself brought down. This reversal-of-pride theology is central to Isaiah\'s theodicy (cf. Isa 2:12-17).</p>',
    "16": '<p><strong>wayyigbaĥ YHWH ṣĕḇāʾôt bammišpāṭ</strong> = "but YHWH of hosts is exalted (<em>gāḇah</em>) in justice (<em>mišpāṭ</em>)." Ironic reversal: man descends, YHWH ascends — in the very act of judgment. <strong>wĕhāʾēl haqqādôš niqdaš biṣĕdāqâ</strong> = "the Holy God shows himself holy (<em>niqdaš</em>, niphal reflexive of <em>qādaš</em>) in righteousness." Holiness is not merely a status; it is demonstrated in righteous action against injustice.</p>',
    "17": '<p><strong>wĕrāʿû ḵĕḇāśîm kĕdoḇrām</strong> = "and lambs shall graze as in their pasture." After human judgment, nature reclaims what was over-cultivated by the greedy. <strong>wĕḥurāḇôt mēʾîm gārîm yōʾkēlû</strong> = "and the ruins of the fat ones (<em>mēʾîm</em>) will be eaten by migrants (<em>gārîm</em>)" — the accumulated wealth of the wealthy becomes food/pasture for those they displaced. Poetic justice in agricultural terms.</p>',
    "18": '<p>Third woe: those who drag sin behind them like a cart. <strong>hôy môšĕkê heʿāwōn bĕḥaḇlê haššāwĕʾ</strong> = "woe to those who drag iniquity (<em>ʿāwōn</em>) with cords (<em>ḥeḇel</em>) of falsehood (<em>šāwĕʾ</em>)" — sin is a burden requiring effort to pull. <em>ʿĀwōn</em> = guilt/iniquity/punishment; <em>ḥaḇlê šāwĕʾ</em> = ropes of nothingness. <strong>wĕkaʿăḇôt hāʿăgālâ ḥaṭṭāʾâ</strong> = "and sin as with cart (<em>ʿăgālâ</em>) ropes (<em>ʿăḇôt</em>)" — cart ropes are thicker, heavier; sin has become structural, load-bearing.</p>',
    "19": '<p><strong>hāʾōmĕrîm yĕmaher yāḥîšâ maʿăśēhû</strong> = "who say: let him hurry, let him hasten his work" — they mock YHWH\'s slowness to judge, daring him to act. <strong>wĕtiqraḇ wĕtāḇôʾ ʿăṣat qĕdôš yiśrāʾēl</strong> = "and let the plan (<em>ʿēṣâ</em>) of the Holy One of Israel draw near." <em>Qĕdôš yiśrāʾēl</em> = "Holy One of Israel" — one of Isaiah\'s signature divine epithets (25+ occurrences in Isaiah vs. 6 in all other OT books), linking holiness to the divine plan that the mockers challenge.</p>',
    "20": '<p>Fourth woe — the most conceptually radical. <strong>hôy hāʾōmĕrîm lārāʿ ṭôḇ wĕlaṭṭôḇ rāʿ</strong> = "woe to those who call evil good and good evil." Not merely moral confusion but category inversion — deliberate redefinition of moral categories. <strong>śāmîm ḥōšek lĕʾôr wĕʾôr lĕḥōšek</strong> = "who put darkness for light and light for darkness" — cosmological inversion. <strong>śāmîm mar lĕmāṯôq ûmāṭôq lĕmar</strong> = "who put bitter for sweet and sweet for bitter." The reversal descends from moral (good/evil) to cosmic (light/dark) to sensory (bitter/sweet): total perversion of perceivable reality.</p>',
    "21": '<p>Fifth woe: intellectual pride. <strong>hôy ḥăkāmîm bĕʿênêhem ûneḡed pĕnêhem nĕḇōnîm</strong> = "woe to those who are wise in their own eyes (<em>bĕʿênêhem</em>) and shrewd in their own sight." The reflexive self-certification: wisdom that only looks at itself cannot correct itself. Compare Prov 26:12 ("there is more hope for a fool than for a man wise in his own eyes") and Rom 12:16 ("do not be wise in your own sight").</p>',
    "22": '<p>Sixth woe: judicial corruption by those who pride themselves on drinking capacity. <strong>hôy gibbôrê lišĕtôt yāyin wĕʾanšê-ḥayil limSōk šēkār</strong> = "woe to those who are heroes (<em>gibbôrê</em>) at drinking wine and champions (<em>ʾanšê-ḥāyil</em>) at mixing strong drink." The irony: <em>gibbôr</em> = mighty man/military hero — the highest honor title now applied to drinking prowess. The warriors who should defend justice are drunk.</p>',
    "23": '<p><strong>maṣdîqê rāšāʿ ʿēqeḇ šōḥad</strong> = "who acquit (<em>ṣādaq</em>, hiphil) the wicked for a bribe (<em>šōḥad</em>)" — <em>hiphil</em> of <em>ṣādaq</em> = to declare righteous, to acquit; here of the perversion where payment purchases legal vindication of the guilty. <strong>wĕṣidqat ṣaddîqîm yāsîrû mimmennû</strong> = "and take away the righteousness of the righteous" — the innocent condemned while the guilty are acquitted. This concrete charge explains all six woes: drunken leaders sell verdicts.</p>',
    "24": '<p><strong>lākēn kiʾekol-qāš lĕšôn ʾēš</strong> = "therefore as the tongue of fire devours stubble" — judgment metaphors: fire on <em>qāš</em> (stubble) and <em>ḥāšaš</em> (chaff); rot in the root. Simultaneous destruction from above (fire on blossoms) and below (rot in root). <strong>kî māʾăsû ʾet-tôrat YHWH ṣĕḇāʾôt</strong> = "because they have rejected the <em>tôrâ</em> of YHWH of hosts" — the summary charge. <em>Nāʾaṣ</em> = to spurn, treat with contempt. All six woes rest on this single root: refusal of YHWH\'s <em>tôrâ</em>.</p>',
    "25": '<p><strong>wayyiḥar-ʾap YHWH bĕʿammô</strong> = "and the anger (<em>ʾap</em>, lit. "nose/nostril" = anger by synecdoche) of YHWH burned against his people." <strong>wayyēṭ yādô ʿālāw wayyakkēhû</strong> = "he stretched out his hand against them and struck them" — the same hand-extended formula as the Exodus plagues (Exod 7:5; 9:15), now turned against Israel. <strong>bĕkol-zōʾt lōʾ-šāḇ ʾappô</strong> = "for all this, his anger has not turned away" — the refrain repeated in 9:12,17,21; 10:4, marking that judgment has not yet exhausted itself. This verse prepares the extended Assyrian-invasion section (chs. 7-12).</p>',
    "26": '<p><strong>wĕnāśāʾ-nēs laggôyim mērāḥôq</strong> = "and he will raise a signal/banner (<em>nēs</em>) for nations from far away." <em>Nēs</em> = the military signal banner raised to summon troops. <strong>ûšĕraq lô miqqĕṣēh hāʾāreṣ</strong> = "and he will whistle (<em>šārak</em>) for it from the ends of the earth" — the shepherd\'s call or beekeeper\'s call to swarm. YHWH calls Assyria with the ease of summoning animals. <strong>wĕhinnēh mĕhērâ qal yāḇôʾ</strong> = "and behold, it comes swiftly" — the response is instant.</p>',
    "27": '<p>Military description of the Assyrian army: <strong>ʾên-ʿāyēp wĕʾên-kôšēl bô</strong> = "none is weary and none stumbles" — a formidable, disciplined machine. <strong>lōʾ yānûm wĕlōʾ yîšān</strong> = "it does not slumber and does not sleep" — the ironically god-like quality of the invader (cf. Ps 121:4 where only YHWH never sleeps). The enemy that never sleeps is YHWH\'s instrument, not a divine rival.</p>',
    "28": '<p><strong>ʾăšer ḥiṣṣāyw šĕnûnîm</strong> = "whose arrows (<em>ḥēṣ</em>) are sharpened." <strong>kol-qăšĕtōtāw dĕrûkôt</strong> = "all his bows are bent/strung" — drawn and ready. <strong>pārāšāyw</strong> = cavalry; <strong>sus</strong> = horse. The description builds an impression of a fully armed, mechanically precise war machine — opposite of the drunken, sleepy leaders of the woe oracles.</p>',
    "29": '<p><strong>šĕʾāgâ lô kaллābîʾ</strong> = "its roaring is like a lion (<em>laḇîʾ</em>, a lion in its prime)" — <em>šāʾag</em> = the triumph-roar of the successful hunter. <strong>wayyiśʾ kĕkĕpîrîm wayyinhōm</strong> = "it growls like young lions" — not one lion but the pride. <strong>wayyiśʾ tereṗ wĕyaʿăḇōr</strong> = "it seizes prey and carries it off, and none rescues." YHWH himself has become the lion that hunts through his Assyrian instrument.</p>',
    "30": '<p><strong>wĕyinham ʿālāw bayyôm hahûʾ kĕhēmôt yām</strong> = "it will growl over them on that day like the roaring of the sea" — the sea as chaos-power. <strong>wĕnibbaṭ lāʾāreṣ wĕhinnēh-ḥōšek ṣar</strong> = "and if one looks to the earth, behold darkness and distress." The chapter ends at the lowest point: <em>ḥōšek</em> (H2822) and <em>ʿărāpel</em> (H6205) = thick/deep darkness. Yet the darkness gives way (cf. 9:1-2): the chapter ends before the Immanuel oracle begins.</p>'
  },
  "6": {
    "1": '<p><strong>bišnat-mût hammelek ʿuzziyyāhû</strong> = "in the year that King Uzziah died" — 740 BCE. The historical anchor is also theological: Uzziah died as a leper after attempting to usurp the priestly prerogative (2 Chr 26:16-21). Isaiah enters the holy exactly where Uzziah failed — but through vision and prophetic commission. <strong>wāʾereʾ ʾet-ʾădōnāy yōšēḇ ʿal-kissēʾ rām wĕniśśāʾ</strong> = "I saw the Lord (<em>ʾădōnāy</em>, sovereign title) sitting on a high and exalted (<em>rām wĕniśśāʾ</em>) throne." This same pair (<em>yārûm wĕniśśāʾ</em>) is applied to the Suffering Servant in 52:13 — the Servant\'s exaltation echoes the divine throne-vision. <strong>wĕšûlāyw mĕlĕʾîm ʾet-hahêkāl</strong> = "and his skirt-train (<em>šûl</em>) filled the temple" — the divine robe\'s overflow fills the entire sacred space. Divine plenitude overflowing the sacred container.</p>',
    "2": '<p><strong>śĕrāpîm ʿōmĕdîm mimmaʿal lô</strong> = "seraphim were standing above him" — <em>śārāp</em> (H8314) = burning ones, from <em>śārap</em> (to burn). These beings appear only in this passage. <strong>šēš kĕnāpayim šēš kĕnāpayim</strong> = "six wings, six wings" — two cover the face (divine presence is overwhelming even for these beings), two cover the feet (euphemism for genitals: covering their own creaturely nakedness before God), two for flying. The posture: both homage (self-covering) and readiness (wings for flight).</p>',
    "3": '<p><strong>wĕqārāʾ zeh ʾel-zeh wĕʾāmar</strong> = "and one called to another and said" — antiphonal proclamation, liturgical responsorial. <strong>qādôš qādôš qādôš YHWH ṣĕḇāʾôt</strong> = "Holy, holy, holy, LORD of armies." The tripled adjective is unique in the Hebrew Bible (doubled superlatives are common; the triple is without parallel). The triple <em>qādôš</em> is the highest intensity Hebrew can express. <em>Qādôš</em> (H6918) = set apart, wholly other, dangerous in proximity without purification.</p><p><strong>mĕlōʾ kol-hāʾāreṣ kĕḇôdô</strong> = "the fullness of all the earth is his glory (<em>kāḇôd</em>)." <em>Kāḇôd</em> (H3519) = weight, heaviness, glory — the substantial reality of what YHWH is. Not only the temple but the entire creation is filled with and displays this glory.</p>',
    "4": '<p><strong>wayyānūʿû ʾammôt hassippîm miqōl haqqôrēʾ</strong> = "the foundations of the thresholds (<em>ʾammôt hassippîm</em>) shook at the voice of the one calling" — theophanic structural trembling (cf. Exod 19:18; Ps 29:3-9; Rev 15:8). <strong>wĕhabbayit yimmālēʾ ʿāšān</strong> = "and the house was filled with smoke (<em>ʿāšān</em>)" — divine smoke/cloud as the medium of theophany (cf. Exod 19:18; 1 Kgs 8:10-12). The visual, auditory, and structural elements of the theophany are total.</p>',
    "5": '<p><strong>wāʾōmar ʾôy-lî kî-nidmêtî</strong> = "Woe to me, for I am undone/destroyed (<em>nidmêtî</em>)." <em>Nidmêtî</em> = niphal perfect of <em>dāmâ</em> (H1820) = to be cut off, destroyed, silenced. Isaiah experiences the approach of death that proximity to the holy court risks without purification (cf. Exod 33:20). <strong>kî ʾîš ṭĕmēʾ-śĕpātayim ʾānōkî</strong> = "for I am a man of unclean lips" — the mouth is the prophet\'s instrument; his self-indictment goes to the very organ of his calling. <strong>ûḇĕtôk ʿam-ṭĕmēʾ śĕpātayim ʾānōkî yōšēḇ</strong> = "and I dwell in the midst of a people of unclean lips" — the prophet shares the collective guilt of those he will address.</p>',
    "6": '<p><strong>wayyāʿop ʾēlay ʾeḥāḏ min-haśśĕrāpîm</strong> = "and one of the seraphim flew to me." <strong>ûḇĕyādô rizpâ</strong> = "and in his hand was a live coal (<em>rizpâ</em>, H7531)" — glowing coal from the altar. <strong>bĕmilqāḥayim lāqaḥ mēʿal hammizḇēaḥ</strong> = "which he had taken with tongs (<em>milqāḥayim</em>) from the altar" — even the seraph does not handle the altar-fire bare; the holiness of the altar-fire is mediated even for heavenly beings.</p>',
    "7": '<p><strong>wayyaggaʿ ʿal-pî</strong> = "and he touched it to my mouth" — the organ of prophetic speech is the point of purification. <strong>hinnēh nāgaʿ zeh ʿal-śĕpātêkā wĕṣāḇ ʿăwōnêkā</strong> = "Behold, this has touched your lips and your iniquity (<em>ʿāwōn</em>) is removed (<em>ṣāḇ</em>, from <em>sûr</em>) and your sin (<em>ḥaṭṭāʾt</em>) is atoned (<em>kāpar</em>, pual passive)." Two distinct terms: <em>ʿāwōn</em> (guilt-status) and <em>ḥaṭṭāʾt</em> (the act and consequence). Both are dealt with through the burning coal from the altar — pre-Calvary atonement pointing forward to its ground in Christ\'s sacrifice.</p>',
    "8": '<p><strong>wāʾešmaʿ ʾet-qôl ʾădōnāy ʾōmēr ʾet-mî ʾešlaḥ ûmî yēlēk-lānû</strong> = "I heard the voice of the Lord saying: Whom shall I send and who will go for us?" — the divine deliberation in the heavenly council (cf. 1 Kgs 22:19-22; Job 1-2). <em>Lānû</em> = "for us" — the plural is theologically significant: the divine council, anticipating Trinitarian plurality. YHWH does not conscript; he asks. The open question invites voluntary response.</p><p><strong>wāʾōmar hinnēnî šĕlāḥēnî</strong> = "Here am I (<em>hinnēnî</em>)! Send me." <em>Hinnēnî</em> = the word of divine and human readiness/availability (Gen 22:1; 1 Sam 3:4-8). Isaiah\'s response comes from someone who has experienced both his own sinfulness (v5) and purification (vv6-7); the "send me" is informed, not naive. NT: the identical posture is attributed to the incarnate Christ in Heb 2:13.</p>',
    "9": '<p><strong>wayyōʾmer lēk wĕʾāmartā lāʿām hazzeh šimʿû šāmôaʿ wĕʾal-tāḇînû</strong> = "Go and say: Keep on hearing (<em>šāmôaʿ</em>, infinitive absolute + finite verb = emphatic continual hearing) but do not understand (<em>bîn</em>)." The hardening commission. The doubled infinitive absolute (<em>šāmôaʿ</em>/<em>rĕʾô</em>) makes the seeing and hearing infinitely repeated but without resulting comprehension.</p><p>This is among the most NT-cited OT passages: Matt 13:14-15; Mark 4:12; Luke 8:10; John 12:40; Acts 28:26-27; Rom 11:8. The hardening results from persistent rejection of the prophetic word — each refusal desensitizes further; the prophet\'s ministry accelerates this process by confronting a people already committed to rejection. <strong>wĕrĕʾû rāʾô wĕʾal-tēdāʿû</strong> = "keep on seeing but do not know" — perception without transformation.</p>',
    "10": '<p><strong>hašmēn lēḇ hāʿām hazzeh</strong> = "Make the heart of this people fat (<em>šāmēn</em>)" — <em>šāmēn</em> (piel imperative) = to make fat, dull, insensitive; a heart so covered in fat it cannot feel. <strong>wĕʾoznāyw haḵḇēd</strong> = "make its ears heavy (<em>kāḇēd</em>)" — unable to lift/respond. <strong>wĕʿênāyw hāšaʿ</strong> = "and blind its eyes."</p><p>Theologically: Isaiah is commanded to declare truth in a way that results in hardening. The historical explanation: each refusal desensitizes further; the prophet\'s ministry accelerates the process already underway. John 12:40 applies it to Jewish rejection of Jesus; Paul (Rom 11:25) calls it a partial hardening until the fullness of the Gentiles comes in. The hardening is never YHWH\'s final word: v13 ends with the holy seed in the stump.</p>',
    "11": '<p><strong>wāʾōmar ʿad-māttay ʾădōnāy</strong> = "And I said, How long, O Lord?" — Isaiah\'s intercession. <strong>wāyyōʾmer ʿad ʾăšer-ʾim-šāʾû ʿārîm mēʾên yôšēḇ</strong> = "Until cities lie waste without inhabitant." The hardening commission lasts until total desolation — exile, abandoned houses, devastated land. The answer is sobering: the darkening continues until judgment is complete.</p>',
    "12": '<p><strong>wĕriḥaq YHWH ʾet-hāʾādām</strong> = "and YHWH removes mankind far away" — the exile described at its theological core: not merely deportation by armies but YHWH himself removing (<em>riḥaq</em> = to put far away) the people. <strong>wĕraḇâ hāʿăzûḇâ bĕqereḇ hāʾāreṣ</strong> = "and the abandonment (<em>ʿăzûḇâ</em>) multiplied in the land" — the deserted landscape. <em>ʿĂzûḇâ</em> is also a personal name meaning "forsaken," making the land itself personified as the abandoned one.</p>',
    "13": '<p><strong>wĕʿôd bāh ʿăśîriyyâ wĕšāḇâ wĕhāyĕtâ lĕḇaʿēr</strong> = "if a tenth remains and returns, it will be burned again" — even the tenth (the tithe-proportion) faces the fire. Yet: <strong>kāʾēlâ wĕkāʾallôn ʾăšer bĕšalleket maṣṣeḇet bām</strong> = "like a terebinth and oak whose stump (<em>maṣṣeḇet</em>) remains when felled" — apparent totality of destruction leaves a stump. <strong>zereʿ qōdeš maṣṣaḇtāh</strong> = "the holy seed (<em>zereʿ qōdeš</em>) is its stump." The stump = the remnant from which growth comes again. This is the seed of the Messiah, the "branch" of 11:1 that grows from Jesse\'s stump. The entire hardening commission (vv9-13) ends with a seed-promise.</p>'
  },
  "7": {
    "1": '<p>Historical context: the Syro-Ephraimitic War (ca. 735 BCE). <strong>Reṣîn melek ʾărām wûpĕqaḥ ben-Rĕmalyāhû melek yiśrāʾēl</strong> = Rezin of Syria and Pekah of Israel — the northern coalition forcing Judah (under Ahaz) to join their anti-Assyrian alliance. <strong>wĕlōʾ yāḵĕlû lĕhillāḥēm ʿālāyw</strong> = "but they were not able to fight against it" — despite threatening Jerusalem, the attack failed. Isaiah\'s task (vv3-9): assure Ahaz that this threat will not succeed.</p>',
    "2": '<p><strong>wayyānāʿ lĕḇāḇô ûlĕḇab ʿammô kĕnôaʿ ʿăṣê-yaʿar</strong> = "his heart and the heart of his people shook like trees of the forest before the wind." <em>Nûaʿ</em> (H5128) = to shake, totter. The collective panic is portrayed with the simile of wind-shaken trees — the same verb (<em>nûaʿ</em>) appears in 10:34 when YHWH shakes the forest of Assyrian pride. The instrument of terror will itself be shaken.</p>',
    "3": '<p>YHWH sends Isaiah and <strong>šĕʾār yāšûḇ bĕnô</strong> = "his son Shear-jashub" — the name means "a remnant will return." The child\'s presence is a walking sign-act: there will be a remnant, but only a remnant. Isaiah meets Ahaz <strong>biqṣēh tĕʿālat habĕrēkâ hāʿelyônâ</strong> = "at the end of the conduit of the upper pool" — an engineering landmark related to Jerusalem\'s water supply, possibly where Hezekiah later built his tunnel (2 Kgs 20:20). The mundane location for a divine message is characteristically prophetic.</p>',
    "4": '<p><strong>hiššāmer wĕhašqēṭ ʾal-tîrāʾ</strong> = "Take heed, be quiet, do not fear" — three imperatives of the prophetic assurance formula. <strong>ûlĕḇāḇĕkā ʾal-yirk</strong> = "do not let your heart grow soft (<em>rākaḵ</em>)" — <em>rākaḵ</em> = to be timid (opposite of firm). <strong>mišĕnê zanĕḇôt hāʾûdîm hāʿăšēnîm hāʾēlleh</strong> = "before these two smoldering (<em>ʿāšēn</em>) stumps of firebrands (<em>ʾûd</em>)" — Rezin and Pekah are not roaring lions but dying embers, stumps of old torches with more smoke than fire.</p>',
    "5": '<p><strong>yaʿan kî yāʿaṣ ʿālêkā ʾărām rāʿâ</strong> = "because Syria has planned evil against you." <strong>Eprayim ûben-Rĕmalyāhû</strong> = Ephraim (northern Israel) and "the son of Remaliah" — the latter used 5 times in this section instead of Pekah\'s name; a subtle dismissal of his royal dignity (cf. v9: "the head of Ephraim is the son of Remaliah").</p>',
    "6": '<p><strong>naʿăleh ḇiyĕhûdâ ûnĕqîṣennâ</strong> = "Let us go up against Judah and terrorize it." The coalition plans to replace Ahaz with a puppet king, <strong>ben-ṭāḇĕʾal</strong> = "son of Tabeel" — a non-Davidic figure. The threat is not merely military conquest but termination of the Davidic dynasty — which is why the Immanuel promise matters: the house of David will not be extinguished.</p>',
    "7": '<p><strong>kōh ʾāmar ʾădōnāy YHWH lōʾ tāqûm wĕlōʾ tihyeh</strong> = "Thus says the Lord YHWH: It shall not stand, and it shall not come to pass." <em>Qûm</em> = to arise/stand (of a plan becoming reality). The conspiracy against the Davidic house will fail because YHWH\'s promise to David\'s line (2 Sam 7; Ps 89) is irrevocable.</p>',
    "8": '<p><strong>kî rōʾš ʾărām Dammāśeq wĕrōʾš Dammāśeq Reṣîn</strong> = "For the head of Syria is Damascus, and the head of Damascus is Rezin" — the political argument: the coalition\'s strength is limited by geography; Damascus is merely its capital and Rezin merely its king. <strong>wĕʾôd šiššîm wĕḥāmēš šānâ yēḥat ʾEprayim mēʿām</strong> = "and within sixty-five years Ephraim will be shattered from being a people" — fulfilled in stages: 722 BCE (Sargon II\'s deportation) and ca. 670 BCE (Esarhaddon\'s repopulation).</p>',
    "9": '<p><strong>wĕrōʾš ʾEprayim Šōmrôn wĕrōʾš Šōmrôn ben-Rĕmalyāhû</strong> = "the head of Ephraim is Samaria and the head of Samaria is the son of Remaliah" — Pekah deflated to mere "son of Remaliah," a regional governor at best.</p><p><strong>ʾim lōʾ taʾămînû kî lōʾ tēʾāmēnû</strong> = "If you will not believe (<em>taʾămînû</em>), surely you shall not be established (<em>tēʾāmēnû</em>)" — the famous Hebrew wordplay on <em>ʾāman</em> (H539): the root of both "believe/trust" and "be established/firm." Faith in YHWH\'s word is the basis of political and personal stability; without the former the latter cannot exist. This verse is crucial for NT understanding of faith-as-foundation (cf. Rom 1:17; Heb 11:1: <em>pistis</em> as the "substance/foundation" of things hoped for).</p>',
    "10": '<p><strong>wayyôsep YHWH dabbēr ʾel-ʾāḥāz</strong> = "and YHWH spoke again to Ahaz" — YHWH presses past Ahaz\'s silence or evasion; the offer of a sign (<em>ʾôt</em>) is a direct invitation to trust. The prophetic word pursues even the unwilling king.</p>',
    "11": '<p><strong>šĕʾal-lĕkā ʾôt mēʿim YHWH ʾĕlōhêkā</strong> = "Ask for a sign (<em>ʾôt</em>) from YHWH your God." <strong>hămēq šĕʾālâ ô hāgbēah lĕmāʿĕlâ</strong> = "as deep as Sheol or as high as the heights above" — the extremes of the cosmos are offered. YHWH\'s generosity will be contrasted with Ahaz\'s refusal.</p>',
    "12": '<p><strong>wāyyōʾmer ʾāḥāz lōʾ-ʾešʾal wĕlōʾ-ʾănasseh ʾet-YHWH</strong> = "I will not ask and I will not put YHWH to the test." Ahaz quotes Deut 6:16 piously — but this is evasion, not faithfulness. He has already decided to seek the Assyrian alliance (2 Kgs 16:7-8) rather than trust YHWH. The refusal of the sign is the refusal of faith, with Deuteronomic language as cover.</p>',
    "13": '<p><strong>wāyyōʾmer šimʿû-nāʾ bêt Dāwid</strong> = "Hear then, O house of David" — Isaiah addresses not just Ahaz but the entire Davidic dynasty; the sign will be for the royal house and its ultimate future. <strong>hĕmeʿaṭ mikkĕm halĕʾôt ʾănāšîm kî talĕʾû gam ʾet-ʾĕlōhāy</strong> = "Is it too little for you to weary men, that you weary my God also?" — Ahaz has exhausted both Isaiah\'s patience and YHWH\'s.</p>',
    "14": '<p><strong>lākēn yittēn ʾădōnāy hûʾ lākem ʾôt</strong> = "Therefore the Lord himself will give you a sign." YHWH overrides Ahaz\'s refusal — not for Ahaz\'s benefit but for the sake of the house of David and its ultimate fulfillment. <strong>hinnēh hāʿalmâ hārâ wĕyōledet bēn wĕqārāʾt šĕmô ʿimmānûʾēl</strong> = "Behold, the young woman (<em>hāʿalmâ</em>) is with child and will bear a son and she will call his name Immanuel (<em>ʿimmānûʾēl</em>) = God with us."</p><p><em>Hāʿalmâ</em> (H5959) = the young woman of marriageable age; the definite article <em>hā-</em> makes this "the particular young woman" (in the immediate context, likely pointing to someone in Isaiah\'s court, cf. 8:3 where Isaiah\'s wife bears a son as a near-sign). <em>Bĕtûlâ</em> (H1330) = virgin specifically; <em>ʿalmâ</em> = young woman who may or may not be a virgin (usage in Gen 24:43 of Rebekah; Song 1:3; 6:8; Exod 2:8). The LXX chose <em>parthenos</em> (virgin), which Matt 1:23 uses. Matthew\'s use is typological: the Immanuel sign had a partial near-fulfillment in Isaiah\'s era; it achieves its ultimate antitype in the miraculous virgin conception of Jesus. The "God with us" name is both the theological claim and the sign\'s content: YHWH has not abandoned the Davidic house.</p>',
    "15": '<p><strong>ḥemʾâ ûdĕḇaš yōʾkēl</strong> = "Curds (<em>ḥemʾâ</em>) and honey (<em>dĕḇaš</em>) he shall eat." Canaan was "flowing with milk and honey" (Exod 3:8), but these subsistence foods in the context of invasion mean the child will grow up in a reduced, war-impoverished land. Curds-and-honey = the food of disrupted agriculture when only pastoral herding and wild honey remain. <strong>lĕdaʿtô lĕmāʾōs bārāʿ ûḇāḥôr baṭṭôḇ</strong> = "by the time he knows to reject the evil and choose the good" — moral discernment as developmental marker; the sign will be fulfilled within a child\'s growing-up span.</p>',
    "16": '<p><strong>kî bĕṭerem yēdaʿ hannaʿar mĕʾōs bārāʿ ûḇāḥōr baṭṭôḇ</strong> = "for before the child knows to refuse the evil and choose the good, the land whose two kings you dread will be deserted." Near-fulfillment: both Rezin and Pekah were defeated (Rezin by 732 BCE, Pekah assassinated ca. 731 BCE) within years — within a child\'s early development. Structure of prophetic fulfillment: partial near-fulfillment (Isaiah\'s era) → ultimate fulfillment (incarnation).</p>',
    "17": '<p><strong>yāḇîʾ YHWH ʿālêkā... yāmîm ʾăšer lōʾ-bāʾû... ʾēt melek ʾAššûr</strong> = "YHWH will bring upon you days not seen since Ephraim separated from Judah — the king of Assyria." The judgment pivots: Ahaz thought Assyria would save him (2 Kgs 16:7); YHWH warns that the Assyrian he courts will become Judah\'s greatest threat. The very instrument Ahaz seeks for protection becomes the instrument of punishment for Ahaz\'s unfaith.</p>',
    "18": '<p><strong>yišrōq YHWH laḏḏĕḇôrâ</strong> = "YHWH will whistle for the fly... and the bee in the land of Assyria" — two great powers, both summoned by YHWH\'s whistle (cf. 5:26). They will cover the land like insect swarms — overwhelming by sheer density. Ahaz\'s political calculus fails to account for YHWH\'s total sovereignty over both powers simultaneously.</p>',
    "19": '<p><strong>ûḇāʾû wĕnāḥû kullām</strong> = "and they shall come and settle everywhere" — in steep ravines (<em>naḥălê bĕṭṭôt</em>), rock crevices (<em>nĕqîqê hassĕlāʿîm</em>), thorn-bushes (<em>nĕʿāṣôṣ</em>), and watered pastures (<em>nĕhālōlîm</em>). No hiding place is exempt; every corner of the land is reached by the invaders.</p>',
    "20": '<p><strong>yĕgallaḥ ʾădōnāy bĕtaʿar haśśĕkîrâ... bĕmelek ʾAššûr</strong> = "the Lord will shave with a razor that is hired — the king of Assyria." The shaving metaphor describes comprehensive defeat/humiliation: the head, the beard, the hair of the legs removed. <em>Šĕʿar hārāglayim</em> = "hair of the feet/legs" = euphemism for pubic hair — the shame is total. Assyria is YHWH\'s barber for a disgraced Judah.</p>',
    "21": '<p><strong>yĕḥayyeh ʾîš ʿeglat bāqār ûštê ṣōʾn</strong> = "a man will keep alive a young cow and two sheep" — the pastoral image of a reduced post-invasion economy. The contrast with pre-invasion prosperity (vineyards, grain fields) is stark: survival subsistence farming replaces commercial agriculture.</p>',
    "22": '<p><strong>wĕhāyâ mērōḇ ʿăśôt ḥālāḇ yōʾkal ḥemʾâ</strong> = "because of the abundance of milk they produce, he will eat curds" — not prosperity but the natural produce of a reduced herd when the complex agricultural economy has been destroyed. Curds and honey = pastoral survivor diet in a depopulated landscape (cf. v15).</p>',
    "23": '<p><strong>kol-māqôm ʾăšer yihyeh-šām ʾelep gepen bĕ-ʾelep kesep lašāmîr wāšît yihyeh</strong> = "every place where there were a thousand vines worth a thousand pieces of silver will become briars and thorns" — the expensive vineyard (1,000 vines = 1,000 shekels) returns to <em>šāmîr wāšît</em> (the Isaiah-pair for cursed wilderness, cf. 5:6). Economic collapse total.</p>',
    "24": '<p><strong>baḥiṣṣîm ûḇaqqeśet yāḇôʾ šāmmâ</strong> = "with arrows and bow one will come there" — the cultivated land becomes hunting ground; former vineyards become wilderness for archers. Inversion of cultivation to wilderness is the judgment pattern of Leviticus 26 and Deuteronomy 28 enacted.</p>',
    "25": '<p><strong>wĕkol-hehārîm ʾăšer bammĕʿdēr yēʿādērûn lōʾ-tāḇôʾ šāmmâ yirʾat šāmîr wāšît</strong> = "all the hills that were cultivated with a hoe — you will not come there for fear of briars and thorns." The terraced hillside vineyards, centuries of labor, revert to thorn-wilderness. <strong>wĕhāyâ lĕmišlaḥ šôr ûlĕmirmas śeh</strong> = "but they will be a place for oxen to roam and for sheep to tread" — subsistence pastoralism replaces commercial viticulture. The judgment of ch5 (the vineyard woes) is now fully enacted.</p>'
  },
  "8": {
    "1": '<p><strong>qah-lĕkā gillāyôn gādôl</strong> = "take a large tablet/scroll (<em>gillāyôn</em>, H1549)" — a polished writing board; large for public visibility. <strong>wĕktoḇ ʿālāyw bĕḥereṭ ʾĕnôš</strong> = "write on it with an ordinary stylus (<em>ḥereṭ ʾĕnôš</em>)" — in common/plain handwriting that anyone can read. The public inscription <strong>māhēr šālāl ḥāš baz</strong> = "swift is plunder, speedy is prey" — the prophetic summary of the Syro-Ephraimitic campaign\'s outcome.</p>',
    "2": '<p><strong>wĕʾāʿîdâ lî ʿēdîm neʾĕmānîm</strong> = "I will take for myself faithful witnesses (<em>ʿēdîm neʾĕmānîm</em>)" — <em>ʿēd</em> (H5707) = legal witness; the inscription is formally testified before fulfillment. <strong>ʾet-Ûriyyâ hakkohen wĕʾet-Zĕkaryāhû ben-Yĕḇerekĕyāhû</strong> = Uriah the priest (probably the high priest who collaborated with Ahaz, 2 Kgs 16:10-16) and Zechariah son of Jeberechiah — credible court witnesses who validate the prophecy.</p>',
    "3": '<p><strong>wāʾeqraḇ ʾel-hannĕḇîʾâ wattahar watteledabbēn</strong> = "I approached the prophetess and she conceived and bore a son" — the prophetess (<em>nĕḇîʾâ</em>) = Isaiah\'s wife (titled by her husband\'s prophetic role). The birth fulfills the Immanuel sign\'s near dimension: a young woman of Isaiah\'s household bears a son as a sign-child. <strong>wayyōʾmer YHWH qĕrāʾ šĕmô māhēr šālāl ḥāš baz</strong> = the name is YHWH\'s command — the child is a living sign-oracle.</p>',
    "4": '<p><strong>kî bĕṭerem yēdaʿ hannaʿar qĕrōʾ ʾāḇî wĕʾimmî</strong> = "for before the child knows to call \'my father\' and \'my mother\'" — the linguistic-developmental marker: pre-speech, the earliest possible span. <strong>yiśśāʾ ʾet-ḥêl Dammāśeq wĕʾēt šĕlal Šōmrôn lipnê melek ʾAššûr</strong> = "the wealth of Damascus and the spoil of Samaria will be carried away before the king of Assyria." Near-fulfillment: Damascus fell 732 BCE, Samaria 722 BCE — within infancy of Maher-shalal-hash-baz. The child\'s infancy is the countdown clock.</p>',
    "5": '<p><strong>wayyôsep YHWH dabbēr ʾēlay ʿôd</strong> = "and YHWH continued speaking to me again" — a new oracle appended, expanding judgment beyond the two northern kingdoms to include Judah itself, since Ahaz chose Assyria over YHWH.</p>',
    "6": '<p><strong>yaʿan kî māʾas hāʿām hazzeh ʾet mê haššilōaḥ hahōlĕḵîm lĕʾaṭ</strong> = "because this people has rejected the waters of Shiloah that flow gently (<em>lĕʾaṭ</em>)." Shiloah (<em>šilōaḥ</em>) = the slow channel supplying Jerusalem\'s water from the Gihon spring (cf. John 9:7 Siloam). Its gently flowing water = YHWH\'s quiet, sufficient provision. Rejected in favor of the roaring Assyrian flood. <strong>wĕśimḥâ ʾet-Reṣîn ûben-Rĕmalyāhû</strong> = "and rejoices over Rezin and the son of Remaliah" — Judah\'s sympathy with the coalition rather than YHWH\'s plan.</p>',
    "7": '<p><strong>hinnēh ʾădōnāy maʿăleh ʿălêhem ʾet-mê hannāhār hāʿăṣûmîm wĕhārabbîm</strong> = "the Lord is bringing up the waters of the River (<em>hannāhār</em> = the Euphrates), mighty and many." The contrast: <em>mê haššilōaḥ hahōlĕkîm lĕʾaṭ</em> (Shiloah\'s gentle stream) vs. <em>mê hannāhār hāʿăṣûmîm</em> (the Euphrates flood). Reject the quiet water; receive the flood. <strong>wĕʿālâ ʿal-kol-ʾăpîqāyw wĕhālak ʿal-kol-gĕḏōtāyw</strong> = "rising over all its channels and going over all its banks."</p>',
    "8": '<p><strong>wĕḥālap bîhûḏâ šāṭap wĕʿāḇar ʿad-ṣawwāʾr yagîaʿ</strong> = "it sweeps into Judah, overflows and passes through, reaching even to the neck" — the flood reaches Judah\'s neck (just short of drowning, cf. 30:28). Not completely submerged: judgment but not annihilation. <strong>wĕhāyâ muttôt kĕnāpāyw mĕlōʾ rōḥaḇ ʾarṣĕkā ʿimmānûʾēl</strong> = "and the outspread of his wings will fill the breadth of your land, O Immanuel." Even in the flood-oracle, the Immanuel name resounds: the land belongs to Immanuel, not to Ahaz.</p>',
    "9": '<p><strong>rōʿû ʿammîm wĕḥōttû</strong> = "Be broken (<em>rāʿaʿ</em>) O peoples, and be shattered (<em>ḥātat</em>)!" — the taunt to the nations: YHWH mocks their pretension. <strong>ʾizzĕrû wĕḥōttû ʾizzĕrû wĕḥōttû</strong> = "gird yourselves and be shattered; gird yourselves and be shattered" — the anaphora of futile military preparation (girding for battle only to be shattered).</p>',
    "10": '<p><strong>ûṣû ʿēṣâ wĕtûpar daḇĕrû dāḇār wĕlōʾ yāqûm kî ʿimmānû ʾēl</strong> = "Take counsel and it will be frustrated; speak a word and it will not stand, for God is with us (<em>ʿimmānû ʾēl</em>)." The nations\' plans are futile because of Immanuel. The name becomes a war-cry against the coalition. Note: <em>ʿimmānû ʾēl</em> here is YHWH\'s presence with Judah; in Matt 1:23 the same declaration is the name of the incarnate Son.</p>',
    "11": '<p><strong>kî kōh ʾāmar YHWH ʾēlay kĕḥizqat hayyād wĕyisĕrēnî</strong> = "For thus YHWH said to me, with strong hand (<em>kĕḥizqat hayyād</em>)" — the grip of prophetic compulsion; the same phrase used of Ezekiel\'s prophetic experiences (Ezek 3:14; 8:1). <strong>lĕbiltî lēket bĕdereḵ hāʿām hazzeh</strong> = "not to walk in the way of this people" — Isaiah warned not to adopt the political fearfulness of the people. The prophet must operate from a different epistemology.</p>',
    "12": '<p><strong>lōʾ-tōʾmrûn qešer lĕkōl ʾăšer-yōʾmar hāʿām hazzeh qāšer</strong> = "Do not call conspiracy (<em>qeśer</em>) everything that this people calls a conspiracy" — the people\'s fear-driven conspiracism. <strong>wĕʾet-môrāʾô lōʾ-tîrāʾû wĕlōʾ taʿărîṣû</strong> = "do not fear what they fear, do not be in dread (<em>ʿāraṣ</em>)" — two different words for dread and terror. The prophet must not be shaped by collective political anxiety.</p>',
    "13": '<p><strong>ʾet-YHWH ṣĕḇāʾôt ʾōtô taqddîšû</strong> = "YHWH of armies — him you shall sanctify (<em>qiddaš</em>, piel)." <strong>wĕhûʾ môrāʾăkem wĕhûʾ maʿărîṣăkem</strong> = "he shall be your fear and he shall be your dread" — the same two words for terror (v12) are now redirected: YHWH becomes the object of the awe that displaces political fear. 1 Pet 3:14-15 cites this verse: "Do not fear their threats... but sanctify Christ as Lord."</p>',
    "14": '<p><strong>wĕhāyâ lĕmiqdāš ûlĕʾeben negeṗ ûlĕṣûr mikšôl</strong> = "he will become a sanctuary (<em>miqdāš</em>) and a stone of stumbling (<em>ʾeben negeṗ</em>) and a rock of offense (<em>ṣûr mikšôl</em>)" — the same divine presence is both sanctuary (refuge) and stumbling stone (occasion of fall). <strong>ûlĕpāḥ ûlĕmôqēš lĕyôšēḇ Yĕrûšālaim</strong> = "and a trap and a snare for the inhabitants of Jerusalem."</p><p>The stone imagery is absorbed into NT Christology: Rom 9:33 ("a stone of stumbling and a rock of offense"); 1 Pet 2:8 ("a stone of stumbling and a rock of offense"); Jesus cites Ps 118:22 (the rejected stone becoming cornerstone, Luke 20:17-18) in the same framework. The stumbling stone that is also a sanctuary is the tension resolved only in Christ: those who trust him find refuge; those who reject him stumble on him.</p>',
    "15": '<p><strong>wĕkāšĕlû bām rabbîm wĕnāpĕlû wĕniśbārû wĕnôqĕšû wĕnilkādû</strong> = "and many shall stumble (<em>kāšal</em>) on them and fall and be broken and be snared and be taken" — five verbs cascading: fall → breaking → ensnaring → capture. Total disaster for those who treat YHWH\'s word as an obstacle. Paul applies this to Israel\'s stumbling over the gospel (Rom 9:32-33); Peter applies it to those who reject the cornerstone (1 Pet 2:8).</p>',
    "16": '<p><strong>ṣôr tĕʿûḏâ ḥătôm tôrâ bĕlimmûdāy</strong> = "Bind up the testimony (<em>tĕʿûḏâ</em>), seal the teaching (<em>tôrâ</em>) among my disciples (<em>limmûdāy</em>)." <em>Limmûdāy</em> = those who have been taught/disciples. This is the earliest use of a "disciples" concept in the prophets: Isaiah has a circle of learners who will preserve the prophetic word when the general population rejects it. The sealing is for safekeeping until fulfillment demonstrates its truth.</p>',
    "17": '<p><strong>wĕḥikkîtî laYHWH hammastîr pānāyw mibbayt yaʿăqōb</strong> = "and I will wait for YHWH who is hiding his face (<em>hammastîr pānāyw</em>) from the house of Jacob." <em>Ḥāḵâ</em> (H2442) = to wait with earnest expectation; <strong>wĕqiwwîtî lô</strong> = "and I will hope in him" — <em>qāwâ</em> (H6960) = the wait of expectation (same word as 40:31). Heb 2:13 directly cites this verse ("I will put my trust in him") as words of Christ — the Servant/Son trusting the Father in the hiddenness of incarnation/passion.</p>',
    "18": '<p><strong>hinnēh ʾānōkî wĕhayĕlādîm ʾăšer nātan-lî YHWH lĕʾōtôt ûlĕmôpĕtîm bĕyiśrāʾēl</strong> = "Behold, I and the children whom YHWH has given me are signs (<em>ʾōtôt</em>) and portents (<em>mōpĕtîm</em>) in Israel." Isaiah and his sign-children (Shear-jashub = "a remnant shall return"; Maher-shalal-hash-baz = "swift is plunder") are living oracles. <strong>mēʿim YHWH ṣĕḇāʾôt haššōkēn bĕhar-ṣiyyôn</strong> = "from YHWH of armies, who dwells on Mount Zion." Heb 2:13 directly quotes this verse, placing it in Christ\'s mouth: "Behold, I and the children God has given me" — the children = those who share Christ\'s flesh and blood, those he calls brothers (Heb 2:11-14).</p>',
    "19": '<p><strong>wĕkî yōʾmĕrû ʾălêkem dirĕšû ʾel-hāʾōḇôt wĕʾel-hayyiḏdĕʿōnîm</strong> = "when they say: Consult the mediums (<em>ʾōḇôt</em>) and the spiritists (<em>yiḏdĕʿōnîm</em>)." <em>ʾĀḇôt</em> = "ghost-pits" or the spirits summoned through them; <em>yiḏdĕʿōnîm</em> = "knowing ones," familiar spirits. <strong>hameṣapṣĕpîm wĕhammĕhagîm</strong> = "who chirp and mutter" — the sound-description of spirit-communication (cf. Matt 12:43-45 where Jesus uses spirit-language in a related context). <strong>hălôʾ ʿam ʾel-ʾĕlōhāyw yiḏrōš</strong> = "should not a people consult their God?" — the obvious counter: YHWH is the living God who speaks through prophets.</p>',
    "20": '<p><strong>lĕtôrâ wĕlitĕʿûḏâ</strong> = "To the <em>tôrâ</em> and to the testimony!" — the standard is YHWH\'s revealed word, the <em>tôrâ-tĕʿûḏâ</em> pair = the whole prophetic deposit (cf. v16). <strong>ʾim-lōʾ yōʾmĕrû kaḏḏāḇār hazzeh ʾăšer ʾên-lô šāḥar</strong> = "if they do not speak according to this word, there is no dawn (<em>šāḥar</em>) for them." The test: those who speak against <em>tôrâ</em> have no light. The darkness they inhabit is their judgment — until the dawn of ch9 breaks.</p>',
    "21": '<p><strong>wĕʿāḇar bāh niqšeh wĕrāʿēḇ wĕhāyâ kî-yirʿaḇ wĕhitqaṣṣap</strong> = "they will pass through the land, hard pressed and hungry; when they are hungry they will be enraged (<em>qāṣap</em>)." The social unraveling of judgment: hunger and desperation. <strong>wĕqillēl bĕmalkô ûḇĕʾĕlōhāyw ûpānâ lĕmāʿĕlâ</strong> = "and will curse their king and their God, looking upward" — blame God and king in anger rather than turning to God in prayer.</p>',
    "22": '<p><strong>wĕʾel-ʾereṣ yabiṭ wĕhinnēh ṣārâ waḥăšēḵâ</strong> = "and they will look to the earth, and behold, distress (<em>ṣārâ</em>) and darkness (<em>ḥăšēḵâ</em>)." Looking up: cursing; looking down: anguish. No direction offers relief. <strong>ûʾăpēlâ mĕnuddāḥ</strong> = "and into thick darkness (<em>ʾăpēlâ</em>) they are driven away (<em>nāḏaḥ</em>)" — ends at the darkest point. But this is the pivot: ch9:1-7 opens immediately with <em>the people who walked in darkness have seen a great light</em> — the Immanuel oracle finds its completion in the Light that breaks from this very darkness.</p>'
  }
}

def main():
    data = load_comm('mkt-original', 'isaiah')
    before = sum(len(v) for v in data.values())
    merge_comm(data, ISAIAH)
    save_comm('mkt-original', 'isaiah', data)
    after = sum(len(v) for v in data.values())
    print(f'  verses: {before} → {after} (+{after - before})')

if __name__ == '__main__':
    main()
